cat >> internal/syncengine/state.go <<'EOF'

// basePairsEqual reports whether two base maps are identical.
func basePairsEqual(a, b map[string]BaseEntry) bool {
	if len(a) != len(b) {
		return false
	}
	for k, va := range a {
		vb, ok := b[k]
		if !ok || va != vb {
			return false
		}
	}
	return true
}
EOF
go build ./... && go test -count=1 ./internal/syncengine/ 2>&1 | tail -1 && go build -o caravan .

